// 0. Resetear la memoria temporal en cada ejecución manual para no congelar datos viejos
const staticData = $getWorkflowStaticData('global');
delete staticData.stockRestante; 
staticData.stockRestante = {};

const resultados = [];

// 1. Obtener datos del Medicamento (Get a row) y del Pedido (Code in JavaScript1)
const medicamentosInput = $input.all(); 
const pedidosInput = $('Code in JavaScript1').all(); 

for (let i = 0; i < medicamentosInput.length; i++) {
  const medData = medicamentosInput[i].json;
  const pedidoData = pedidosInput[i]?.json || {};

  // Separar y preservar los IDs explícitos de cada tabla
  const idPedido = pedidoData.id;
  const idMedicamento = medData.id;

  // Unir ambos datos en un solo objeto
  const itemCombinado = { ...pedidoData, ...medData };

  const nombreMed = itemCombinado.nombre_medicamento || 'Sin Nombre';
  const stockEnBD = parseInt(itemCombinado.stock) || 0;

  if (staticData.stockRestante[nombreMed] === undefined) {
    staticData.stockRestante[nombreMed] = stockEnBD;
  }

  let stockDisponible = staticData.stockRestante[nombreMed];

  // 2. Determinar la cantidad real requerida (priorizar cantidad_pendiente si existe)
  let rawCantidad = itemCombinado.cantidad_pendiente !== undefined && itemCombinado.cantidad_pendiente !== null && Number(itemCombinado.cantidad_pendiente) > 0
    ? itemCombinado.cantidad_pendiente 
    : itemCombinado.cantidad_solicitados;

  let cantidadNecesaria = 0;
  if (typeof rawCantidad === 'string' && String(rawCantidad).includes(',')) {
    cantidadNecesaria = String(rawCantidad).split(',').reduce((acc, val) => acc + (parseInt(val.trim()) || 0), 0);
  } else {
    cantidadNecesaria = parseInt(rawCantidad) || 0;
  }

  // 3. Cálculo de entrega (Total o Parcial)
  let cantidadAEntregar = 0;
  let cantidadPendienteNueva = 0;

  if (stockDisponible >= cantidadNecesaria) {
    cantidadAEntregar = cantidadNecesaria;
    cantidadPendienteNueva = 0;
    stockDisponible -= cantidadNecesaria;
  } else if (stockDisponible > 0) {
    cantidadAEntregar = stockDisponible;
    cantidadPendienteNueva = cantidadNecesaria - stockDisponible;
    stockDisponible = 0;
  } else {
    cantidadAEntregar = 0;
    cantidadPendienteNueva = cantidadNecesaria;
  }

  // 4. Guardar stock restante actualizado en la memoria
  staticData.stockRestante[nombreMed] = stockDisponible;

  resultados.push({
    json: {
      ...itemCombinado,
      id: idMedicamento,                      // ID de la tabla Medicamentos
      id_medicamento: idMedicamento,          // Copia directa
      id_pedido: idPedido,                    // ID de la tabla Pedidos
      cantidad_entregado_calculada: cantidadAEntregar,
      cantidad_pendiente_calculada: cantidadPendienteNueva,
      nuevo_stock_medicamento: stockDisponible
    }
  });
}

return resultados;

const resultados = [];

for (const item of $input.all()) {
  const row = item.json;

  // Separar los textos por comas
  const medicamentos = String(row.medicamentos_solicitados || '').split(',');
  const solicitados = String(row.cantidad_solicitados || '').split(',');
  const pendientes = String(row.cantidad_pendiente || '').split(',');

  // Crear un ítem individual por cada medicamento encontrado
  medicamentos.forEach((med, index) => {
    const nombreLimpio = med.trim();
    if (nombreLimpio) {

      // Obtener los valores numéricos exactos
      const valSolicitado = parseInt(solicitados[index]);
      const valPendiente = parseInt(pendientes[index]);

      const cantSolicitados = isNaN(valSolicitado) ? 1 : valSolicitado;
      const cantPendiente = isNaN(valPendiente) ? 0 : valPendiente;

      // 🎯 FILTRO CLAVE: Solo incluir en la salida si la cantidad pendiente es MAYOR a 0
      if (cantPendiente > 0) {
        resultados.push({
          json: {
            ...row,
            nombre_medicamento: nombreLimpio,
            cantidad_solicitados: cantSolicitados,
            cantidad_pendiente: cantPendiente
          }
        });
      }
    }
  });
}

return resultados;
